module binary_adder_4bit (
    input wire [3:0] a,
    input wire [3:0] b,
    input wire cin,
    output wire [3:0] sum,
    output wire cout
);

    wire [4:0] obf_full_sum;

    assign obf_full_sum = a + b + cin;
    assign sum = obf_full_sum[3:0];
    assign cout = obf_full_sum[4];

endmodule
